import React, { useState } from "react";
import { api } from "../../api";

export default function RegisterPage({onNavigate }) {
    const [formData, setFormData] = useState({
        username: "",
        email: "",
        password: "",
        confirmPassword: ""
    });

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (formData.password !== formData.confirmPassword) {
            alert("Пароли не совпадают!");
        return;
        }

        try {
        await api.register(formData);
        alert("Регистрация успешна!");
        navigate("/login"); // Перенаправляем на вход
        } catch (error) {
            alert("Ошибка при регистрации: " + error.response?.data?.error);
        }
    };

    return (
        <div className="page">
            <div className="container" style={{ maxWidth: '400px', marginTop: '100px' }}>
                <div className="modal"> {/* Используем класс modal для стиля карточки */}
                    <div className="modal__header">
                        <div className="modal__title">Регистрация в Bear Shop</div>
                    </div>
                
                    <form className="form" onSubmit={handleSubmit}>
                        <label className="label">
                        Имя пользователя
                        <input 
                            className="input" 
                            type="text"
                            value={formData.username}
                            onChange={e => setFormData({...formData, username: e.target.value})}
                            required 
                        />
                        </label>

                        <label className="label">
                            Email
                            <input 
                                className="input" 
                                type="email"
                                value={formData.email}
                                onChange={e => setFormData({...formData, email: e.target.value})}
                                required 
                            />
                        </label>

                        <label className="label">
                            Пароль
                            <input 
                                className="input" 
                                type="password"
                                value={formData.password}
                                onChange={e => setFormData({...formData, password: e.target.value})}
                                required 
                            />
                        </label>

                        <label className="label">
                            Подтвердите пароль
                            <input 
                                className="input" 
                                type="password"
                                value={formData.confirmPassword}
                                onChange={e => setFormData({...formData, confirmPassword: e.target.value})}
                                required 
                            />
                        </label>

                        <button type="submit" className="btn btn--primary" style={{ marginTop: '10px' }}>
                            Зарегистрироваться
                        </button>
                        
                        <div style={{ textAlign: 'center', fontSize: '13px', marginTop: '10px', opacity: 0.7 }}>
                            Уже есть аккаунт? <Link to="/login" style={{ color: '#818cf8' }}>Войти</Link>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
}
